import React, { useState } from 'react';

function SearchComponent({ entityName, entityIdKey, onSearch, onEdit, onDelete }) {
  const [searchId, setSearchId] = useState('');
  const [searchResult, setSearchResult] = useState(null);
  const [searchError, setSearchError] = useState(null);

  const handleSearchClick = async () => {
    if (!searchId) {
      setSearchError(`Please enter a ${entityName} ID.`);
      setSearchResult(null);
      return;
    }
    setSearchError(null);
    try {
      const record = await onSearch(searchId);
      setSearchResult(record);
      setSearchError(null);
    } catch (err) {
      setSearchResult(null);
      setSearchError(err.message || 'Record not found.');
    }
  };

  return (
    <div style={{ border: '1px solid #ccc', padding: '15px', margin: '20px 0', background: '#f9f9f9' }}>
      <h3>Search {entityName} by ID</h3>
      <input
        type="number"
        value={searchId}
        onChange={(e) => setSearchId(e.target.value)}
        placeholder={`Enter ${entityName} ID`}
        style={{ padding: '8px', marginRight: '10px' }}
      />
      <button onClick={handleSearchClick} style={{ padding: '8px 15px' }}>Search</button>

      {searchError && <p style={{ color: 'red', marginTop: '10px' }}>{searchError}</p>}

      {searchResult && (
        <div style={{ marginTop: '15px', borderTop: '1px dashed #ccc', paddingTop: '10px' }}>
          <h4>Search Result: (ID: {searchResult[entityIdKey]})</h4>
          <pre style={{ background: '#eee', padding: '10px', overflowX: 'auto' }}>
            {/* Show formatted JSON data, omitting the ID used in the table/form */}
            {JSON.stringify(searchResult, null, 2)}
          </pre>
          <button onClick={() => onEdit(searchResult)}>Edit This Record</button>
          <button 
              onClick={() => onDelete(searchResult[entityIdKey])} 
              style={{ marginLeft: '10px', color: 'red' }}
          >
              Delete This Record
          </button>
        </div>
      )}
    </div>
  );
}

export default SearchComponent;
